const input = $('Workflow Input').item.json;
const orders = $input.all();

if (!orders || orders.length === 0) {
  return [{
    json: {
      found: false,
      message: `Nie znaleziono zamówienia o numerze ${input.order_number}.`
    }
  }];
}

const order = orders[0].json;

// Build tracking URL based on carrier
const getTrackingUrl = (carrier, trackingNumber) => {
  if (!trackingNumber) return null;

  const urls = {
    'InPost': `https://inpost.pl/sledzenie-przesylek?number=${trackingNumber}`,
    'DPD': `https://tracktrace.dpd.com.pl/parcelDetails?typ=1&numer=${trackingNumber}`,
    'DHL': `https://www.dhl.com/pl-pl/home/tracking/tracking-express.html?tracking-id=${trackingNumber}`,
    'Poczta Polska': `https://emonitoring.poczta-polska.pl/?numer=${trackingNumber}`
  };

  return urls[carrier] || null;
};

// Get status message based on order status
const getStatusMessage = (status, carrier) => {
  const messages = {
    'new': 'Zamówienie zostało przyjęte i oczekuje na realizację.',
    'processing': 'Zamówienie jest w trakcie pakowania w naszym magazynie.',
    'shipped': `Przesyłka została nadana przez kuriera ${carrier || 'kuriera'}. Możesz śledzić jej status.`,
    'delivered': 'Przesyłka została dostarczona.',
    'returned': 'Zamówienie zostało zwrócone.'
  };
  return messages[status] || 'Status nieznany.';
};

// Estimate delivery based on status
const getEstimatedDelivery = (status, carrier) => {
  if (status === 'delivered') return 'Dostarczone';
  if (status === 'returned') return 'Zwrócone';
  if (status === 'new' || status === 'processing') return 'Szacowany czas: 2-4 dni robocze od wysyłki';
  if (status === 'shipped') {
    // For demo, estimate 1-2 days from now
    const today = new Date();
    const delivery = new Date(today);
    delivery.setDate(delivery.getDate() + 2);
    return `Szacowana dostawa: ${delivery.toLocaleDateString('pl-PL')}`;
  }
  return 'Nieznany';
};

let shippingAddress = order.shipping_address;
if (typeof shippingAddress === 'string') {
  shippingAddress = JSON.parse(shippingAddress);
}

const trackingUrl = getTrackingUrl(order.carrier, order.tracking_number);

return [{
  json: {
    found: true,
    order_number: order.order_number,
    status: order.status,
    status_message: getStatusMessage(order.status, order.carrier),
    carrier: order.carrier,
    shipping_method: order.shipping_method,
    tracking_number: order.tracking_number || 'Brak - przesyłka jeszcze nie została nadana',
    tracking_url: trackingUrl || 'Niedostępny - przesyłka jeszcze nie została nadana',
    estimated_delivery: getEstimatedDelivery(order.status, order.carrier),
    delivery_address: shippingAddress ? (
      shippingAddress.paczkomat 
        ? `Paczkomat ${shippingAddress.paczkomat}, ${shippingAddress.city}`
        : `${shippingAddress.street}, ${shippingAddress.postal_code} ${shippingAddress.city}`
    ) : 'Nieznany'
  }
}];
